#include <bits/stdc++.h>
using namespace std;

const int N=1e6+5;

int n,a,f[N][21],c[N],dep[N],bu,bv;
//f[i][j]存储节点i向上2^j的节点(没有则为0)，c[i]为差分数组，dep[i]为节点i的深度
vector<int> g[N];

void dfs(int x){
    dep[x]=dep[f[x][0]]+1;//如果为0则是0(因为dep[0]是全局变量)+1=1
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(g[x][i]!=f[x][0]){
            int v=g[x][i];
            f[v][0]=x;//v的父亲为x
            for(int j=1;f[f[v][j-1]][j-1];j++)
                f[v][j]=f[f[v][j-1]][j-1];//将向上跳2^j步拆解为2^(j-1)+2^(j-1)步
            dfs(v);
        }
}

void Sum(int x){
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(g[x][i]!=f[x][0]){
            Sum(g[x][i]);
            c[x]+=c[g[x][i]];//求和
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=20;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    //先让x上跳到与y同层 
    if(x==y)
        return x;//相等则说明x为x,y的最近公共祖先
    for(int i=20;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];//如果不相等就上跳
    return f[x][0];//此时x和y的最近公共祖先为x(或y)的父亲
}

int main(){
    scanf("%d%d",&n,&a);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1);//设置dep,f数组
    for(int i=1,u,v;i<=a;i++){
        scanf("%d%d",&u,&v);
        int fa=LCA(u,v);
        c[u]++,c[f[fa][0]]--;
        c[v]++,c[fa]--;
    }
    scanf("%d%d",&bu,&bv);
    Sum(1);//将c相加
    //类似倍增地暴力遍历bu到bv这条路径上的点
    int x=bu,y=bv,ans=0;
    if(dep[x]<dep[y])
        swap(x,y);
    while(dep[x]>dep[y]){
        if(!c[x])
            ans++;//如果节点未被染色，则其可被删除，令答案增加
        x=f[x][0];
    }
    while(x!=y)
		ans+=(!c[x])+(!c[y]),x=f[x][0],y=f[y][0];
    ans+=(!c[x]);//算上最近公共祖先
    printf("%d",ans);
    return 0;
}
